mapper.select:
SELECT a.id, a.house_id, a.item_group, a.item_code, a.item_name, a.standard_id, a.start_date, a.expire_date, a.last_date, a.last_reading, a.this_reading, a.qty, a.money, a.standard_price, a.max_price, a.price_formula, a.trade_times, a.max_money, a.money_formula, a.is_free, a.reason, a.preferential, a.deduction, a.latefee, a.receivable, a.paid_in, a.final_money, a.overdue_day, a.is_charged, a.charged_time, a.record_id, a.delay_date, a.heat_usage, a.is_calc, a.is_closed, a.year, a.month, a.org_id, a.parking_space_id, b.room_num, c.user_name, d.building_name, e.parking_code, e.parkinglot_name FROM pr_expense a LEFT JOIN pr_house b ON a.house_id = b.id LEFT JOIN pr_user_house c ON c.house_id = b.id AND c.del_flag = '0' LEFT JOIN pr_building d ON b.building_id = d.id LEFT JOIN pm_parking_space e ON a.parking_space_id = e.id WHERE a.del_flag = '0'
AND a.org_id = #{orgId}
AND b.building_id = #{buildingId}
AND b.unit_code = #{unitCode}
AND a.item_group = #{itemGroup}
AND a.item_code = #{itemCode}
AND a.is_charged = #{isCharged}
AND a.parking_space_id = #{parkingId}
AND (b.room_num LIKE CONCAT('%', #{search}, '%') OR c.user_name LIKE CONCAT('%', #{search}, '%'))
ORDER BY a.create_time DESC

SELECT a.id, a.house_id, a.item_group, a.item_code, a.item_name, a.standard_id,
       a.start_date, a.expire_date, a.money, a.standard_price, a.is_charged,
       b.room_num, c.user_name
FROM pr_expense a
LEFT JOIN pr_house b ON a.house_id = b.id
LEFT JOIN pr_user_house c ON c.house_id = b.id AND c.del_flag = '0'
WHERE a.del_flag = '0'
  AND a.org_id = #{orgId}

    AND b.building_id = #{buildingId}


    AND b.unit_code = #{unitCode}


    AND a.item_group = #{itemGroup}


    AND a.item_code = #{itemCode}


    AND (b.room_num LIKE CONCAT('%', #{search}, '%') OR c.user_name LIKE CONCAT('%', #{search}, '%'))

ORDER BY a.create_time DESC

