mapper.select:
SELECT a.id, a.house_id, a.item_group, a.item_code, a.item_name, a.standard_id,
       a.start_date, a.expire_date, a.money, a.standard_price, a.is_free,
       a.preferential, a.deduction, a.receivable, a.paid_in, a.final_money,
       a.is_charged, a.charged_time, a.parking_space_id, a.qty, a.year, a.month,
       b.room_num, c.user_name, d.building_name,
       e.parking_code, e.parkinglot_name
FROM pr_expense a
LEFT JOIN pr_house b ON a.house_id = b.id
LEFT JOIN pr_user_house uh ON uh.house_id = b.id AND uh.del_flag = '0'
LEFT JOIN pr_user c ON uh.user_id = c.id
LEFT JOIN pr_building d ON b.building_id = d.id
LEFT JOIN pm_parking_space e ON a.parking_space_id = e.id
WHERE a.del_flag = '0'
  AND a.org_id = #{orgId}
AND b.building_id = #{buildingId}
AND b.unit_code = #{unitCode}
AND a.item_group = #{itemGroup}
AND a.item_code = #{itemCode}
AND a.is_charged = #{isCharged}
AND e.parking_id = #{parkingId}
AND (b.room_num LIKE CONCAT('%', #{search}, '%') OR e.parking_code LIKE CONCAT('%', #{search}, '%'))
ORDER BY a.create_time DESC

SELECT a.*, b.org_id, b.org_name, b.building_id, b.building_name, b.unit_code, b.room_num,
       b.other_code, c.user_name, c.phone, d.user_name AS create_by_name
FROM pr_expense_log a
LEFT JOIN pr_house b ON b.id = a.house_id
LEFT JOIN pr_user_house uh ON uh.house_id = b.id AND uh.del_flag = '0'
LEFT JOIN pr_user c ON uh.user_id = c.id
LEFT JOIN sys_user d ON d.id = a.create_by
LEFT JOIN sys_organization e ON e.id = b.org_id
WHERE 1=1
AND b.org_id = #{orgId}
AND b.building_id = #{buildingId}
AND b.unit_code = #{unitCode}
AND e.parent_id = #{parentId}
AND a.log_type = #{type}
AND a.create_time >= #{startTime}
AND a.create_time <= #{endTime}
AND (b.room_num LIKE CONCAT('%', #{search}, '%') OR b.other_code LIKE CONCAT('%', #{search}, '%') OR c.phone LIKE CONCAT('%', #{search}, '%'))
ORDER BY a.create_time DESC

SELECT a.*, b.org_id, b.org_name, b.building_id, b.building_name, b.unit_code, b.room_num,
       c.user_name, c.phone
FROM pr_wechat_order a
LEFT JOIN pr_house b ON b.id = a.house_id
LEFT JOIN pr_user_house uh ON uh.house_id = b.id AND uh.del_flag = '0'
LEFT JOIN pr_user c ON uh.user_id = c.id
LEFT JOIN sys_organization e ON e.id = b.org_id
WHERE 1=1
AND b.org_id = #{orgId}
AND b.building_id = #{buildingId}
AND b.unit_code = #{unitCode}
AND e.parent_id = #{parentId}
AND a.order_status = #{type}
AND a.create_time >= #{startTime}
AND a.create_time <= #{endTime}
AND (b.room_num LIKE CONCAT('%', #{search}, '%') OR b.other_code LIKE CONCAT('%', #{search}, '%') OR c.phone LIKE CONCAT('%', #{search}, '%'))
ORDER BY a.create_time DESC
